import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import BusTracker from './BusTracker';

export default function StudentDashboard() {
  const { user } = useAuth();
  const [passes, setPasses] = useState([]);

  const loadPasses = () => {
    axios.get('/api/pass/my').then(r => setPasses(r.data)).catch(() => {});
  };

  useEffect(() => {
    loadPasses();
  }, []);


  const latest = passes[0];
  const approved = passes.filter(p => p.status === 'approved').length;
  const pending = passes.filter(p => p.status === 'pending').length;

  return (
    <div className="page-container animate-fade-in">
      <h1 className="page-title" style={{ textAlign: 'left', marginBottom: '8px' }}>Welcome, {user?.name} 👋</h1>
      <p style={{ color: 'var(--text-light)', marginBottom: '32px' }}>USN: {user?.usn} · NIE Mysuru</p>

      <div className="stats-grid">
        <div className="stat-card glass-container" style={{ padding: '24px' }}>
          <h3 style={{ color: 'var(--primary-color)' }}>{passes.length}</h3>
          <p>Total Applications</p>
        </div>
        <div className="stat-card glass-container" style={{ padding: '24px' }}>
          <h3 style={{ background: 'var(--success)', WebkitBackgroundClip: 'text' }}>{approved}</h3>
          <p>Approved Passes</p>
        </div>
        <div className="stat-card glass-container" style={{ padding: '24px' }}>
          <h3 style={{ background: 'var(--warning)', WebkitBackgroundClip: 'text' }}>{pending}</h3>
          <p>Pending</p>
        </div>
      </div>

      {latest?.status === 'approved' && (
        <div className="alert alert-success" style={{ display: 'block', padding: '20px 24px', marginBottom: '32px', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <div>
            <div style={{ fontWeight: 700, fontSize: 16, marginBottom: 8 }}>✅ Active Bus Pass</div>
            <div style={{ fontSize: 14 }}>
              Pass No: <strong>{latest.passNumber}</strong> &nbsp;|&nbsp; 
              Route: {latest.from} → {latest.to} &nbsp;|&nbsp; 
              Valid till: <strong>{new Date(latest.validTo).toLocaleDateString()}</strong>
            </div>
          </div>
          <div>
            <Link to={`/renew/${latest._id}`} className="btn btn-outline btn-small">
              Renew Now
            </Link>
            {latest.passImage && (
              <a href={latest.passImage} download className="btn btn-primary btn-small" style={{ marginLeft: '8px' }}>
                Download Pass Image
              </a>
            )}
          </div>
        </div>
      )}

      {latest?.status === 'approved' && (
        <BusTracker passId={latest._id} />
      )}

      {latest?.status === 'expired' && (
        <div className="alert alert-error" style={{ display: 'block', padding: '20px 24px', marginBottom: '32px', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <div>
            <div style={{ fontWeight: 700, fontSize: 16, marginBottom: 8 }}>❌ Expired Bus Pass</div>
            <div style={{ fontSize: 14 }}>
              Your pass <strong>{latest.passNumber}</strong> has expired on <strong>{new Date(latest.validTo).toLocaleDateString()}</strong>.
            </div>
          </div>
          <div>
            <Link to={`/renew/${latest._id}`} className="btn btn-primary btn-small">
              Renew Now
            </Link>
            {latest.passImage && (
              <a href={latest.passImage} download className="btn btn-primary btn-small" style={{ marginLeft: '8px' }}>
                Download Pass Image
              </a>
            )}
          </div>
        </div>
      )}


      {latest?.status === 'rejected' && (
        <div className="alert alert-error" style={{ display: 'block', padding: '20px 24px', marginBottom: '32px', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <div>
            <div style={{ fontWeight: 700, fontSize: 16, marginBottom: 8 }}>❌ Application Rejected</div>
            <div style={{ fontSize: 14 }}>
              <strong>Reason:</strong> {latest.remarks || 'Rejected by Admin'}
            </div>
            {latest.rejectedAt && (new Date() - new Date(latest.rejectedAt)) / (1000 * 60 * 60 * 24) <= 3 && (
              <div style={{ marginTop: '8px', fontSize: 12, color: 'var(--text-light)' }}>
                You have 3 days from rejection to re-upload your documents.
              </div>
            )}
          </div>
          <div>
            {(!latest.rejectedAt || (new Date() - new Date(latest.rejectedAt)) / (1000 * 60 * 60 * 24) <= 3) ? (
              <Link to={`/edit-pass/${latest._id}`} className="btn btn-primary btn-small">
                Edit & Re-upload
              </Link>
            ) : (
              <span style={{ fontSize: 12, color: 'var(--text-light)' }}>Edit window expired</span>
            )}
          </div>
        </div>
      )}

      <div style={{ display: 'flex', gap: '16px', marginBottom: '32px' }}>
        <Link to="/apply" className="btn btn-primary" style={{ width: 'auto' }}>+ Apply for Pass</Link>
        <Link to="/my-passes" className="btn btn-outline" style={{ width: 'auto' }}>View All Passes</Link>
      </div>

      <h2 style={{ fontSize: '1.25rem' }}>Recent Applications</h2>
      <div className="table-container">
        <table className="glass-table">
          <thead>
            <tr>
              <th>Pass No</th>
              <th>Route</th>
              <th>Type</th>
              <th>Applied</th>
              <th>Status</th>
              <th>Action</th>
            </tr>
          </thead>
          <tbody>
            {passes.slice(0, 5).map(p => (
              <tr key={p._id}>
                <td>{p.passNumber || '—'}</td>
                <td>{p.from} → {p.to}</td>
                <td style={{ textTransform: 'capitalize' }}>{p.passType}</td>
                <td>{new Date(p.appliedAt).toLocaleDateString()}</td>
                <td><span className={`badge badge-${p.status}`}>{p.status}</span></td>
                <td>
                  {(p.status === 'approved' || p.status === 'expired') ? (
                    <Link to={`/renew/${p._id}`} className="btn btn-outline btn-small">Renew</Link>
                  ) : <span style={{ color: '#ccc' }}>—</span>}
                </td>
              </tr>
            ))}
            {passes.length === 0 && (
              <tr><td colSpan={6} style={{ textAlign: 'center', color: 'var(--text-light)' }}>No applications yet</td></tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
}
